## 1. RawrXD_GGUF_Preflight.hpp
*Pre-load inspector to predict memory pressure before bad_alloc occurs.*

```cpp
#pragma once
#include <cstdio>
#include <cstdint>
#include <string>
#include <vector>
#include <fstream>
#include <stdexcept>
#include <cstring>

namespace RawrXD::Tools {

struct GGUFMemoryProjection {
    uint64_t total_file_size = 0;
    uint64_t metadata_heap_risk = 0;      // Strings/arrays that could cause bad_alloc
    uint64_t tensor_data_size = 0;        // Raw tensor blob size
    uint64_t header_overhead = 0;         // GGUF header + tensor info
    uint32_t tensor_count = 0;
    uint32_t metadata_kv_count = 0;
    bool contains_800b_model = false;
    std::vector<std::string> high_risk_keys; // Keys requiring skip logic
};

class GGUFInspector {
public:
    static GGUFMemoryProjection Analyze(const char* filepath, bool verbose = false) {
        GGUFMemoryProjection proj;
        FILE* f = nullptr;
        
#ifdef _WIN32
        fopen_s(&f, filepath, "rb");
#else
        f = fopen(filepath, "rb");
#endif
        if (!f) throw std::runtime_error("Failed to open GGUF for inspection");

        // Get file size
        fseek(f, 0, SEEK_END);
        proj.total_file_size = _ftelli64(f);
        fseek(f, 0, SEEK_SET);

        // Read header
        char magic[4];
        if (fread(magic, 1, 4, f) != 4 || memcmp(magic, "GGUF", 4) != 0) {
            fclose(f);
            throw std::runtime_error("Invalid GGUF magic");
        }

        uint32_t version;
        fread(&version, 4, 1, f);
        
        // Reverse-engineered: GGUF v2/v3 use 64-bit counts
        uint64_t tensor_count = 0, metadata_kv_count = 0;
        if (version >= 2) {
            fread(&tensor_count, 8, 1, f);
            fread(&metadata_kv_count, 8, 1, f);
        } else {
            uint32_t tc, mkv;
            fread(&tc, 4, 1, f);
            fread(&mkv, 4, 1, f);
            tensor_count = tc;
            metadata_kv_count = mkv;
        }

        proj.tensor_count = static_cast<uint32_t>(tensor_count);
        proj.metadata_kv_count = static_cast<uint32_t>(metadata_kv_count);

        // Scan metadata keys without loading values
        for (uint64_t i = 0; i < metadata_kv_count; ++i) {
            ScanMetadataEntry(f, proj, verbose);
        }

        // Sum tensor sizes
        for (uint64_t i = 0; i < tensor_count; ++i) {
            SkipTensorInfo(f, proj);
        }

        // Calculate data offset vs file size to detect corruption
        int64_t current_pos = _ftelli64(f);
        proj.tensor_data_size = proj.total_file_size - current_pos;
        proj.header_overhead = current_pos;

        // Heuristic: >100GB tensor data suggests 800B+ class model
        if (proj.tensor_data_size > (100ULL * 1024 * 1024 * 1024)) {
            proj.contains_800b_model = true;
        }

        if (verbose) {
            fprintf(stderr, "[GGUF-INSPECT] File: %s\n", filepath);
            fprintf(stderr, "  Version: %u | Tensors: %llu | Metadata: %llu\n", 
                    version, tensor_count, metadata_kv_count);
            fprintf(stderr, "  High-risk allocations: %llu bytes\n", proj.metadata_heap_risk);
            fprintf(stderr, "  Tensor payload: %.2f GB\n", proj.tensor_data_size / (1024.0 * 1024 * 1024));
            fprintf(stderr, "  800B Class: %s\n", proj.contains_800b_model ? "YES" : "NO");
        }

        fclose(f);
        return proj;
    }

private:
    static uint64_t ReadULEB128(FILE* f) {
        uint64_t result = 0;
        int shift = 0;
        uint8_t byte;
        do {
            if (fread(&byte, 1, 1, f) != 1) break;
            result |= static_cast<uint64_t>(byte & 0x7F) << shift;
            shift += 7;
        } while (byte & 0x80);
        return result;
    }

    static void ScanMetadataEntry(FILE* f, GGUFMemoryProjection& proj, bool verbose) {
        // Skip key string (read length, seek past)
        uint64_t key_len = ReadULEB128(f);
        _fseeki64(f, static_cast<int64_t>(key_len), SEEK_CUR);
        
        // Read value type
        uint32_t val_type;
        fread(&val_type, 4, 1, f);

        // Calculate heap risk based on type
        uint64_t risk_size = 0;
        
        if (val_type == 8) { // GGUF_TYPE_STRING
            uint64_t str_len;
            fread(&str_len, 8, 1, f);
            risk_size = str_len;
            
            // Check if this would cause bad_alloc (>50MB string is suspicious)
            if (str_len > (50 * 1024 * 1024)) {
                char key_name[256] = {0};
                _fseeki64(f, -static_cast<int64_t>(key_len + 8 + 4), SEEK_CUR);
                if (key_len < 256) {
                    fread(key_name, 1, key_len, f);
                    fseek(f, static_cast<int>(8 + 4), SEEK_CUR); // Skip back to data
                } else {
                    fseek(f, static_cast<int>(key_len + 8 + 4), SEEK_CUR);
                }
                
                proj.high_risk_keys.push_back(std::string(key_name, key_len < 256 ? key_len : 0));
                if (verbose) fprintf(stderr, "[RISK] Key '%s' has %llu byte string\n", key_name, str_len);
            }
            
            _fseeki64(f, static_cast<int64_t>(str_len), SEEK_CUR); // Skip data
        }
        else if (val_type == 9) { // GGUF_TYPE_ARRAY
            uint32_t arr_type;
            uint64_t arr_len;
            fread(&arr_type, 4, 1, f);
            fread(&arr_len, 8, 1, f);
            
            // Calculate element size
            uint64_t elem_size = GetGGUFTypeSize(arr_type);
            risk_size = elem_size * arr_len;
            
            if (arr_type == 8) { // Array of strings (merges/tokens)
                // Each element has its own length prefix
                for (uint64_t i = 0; i < std::min(arr_len, 1000ULL); ++i) {
                    uint64_t s_len;
                    fread(&s_len, 8, 1, f);
                    risk_size += s_len;
                    _fseeki64(f, static_cast<int64_t>(s_len), SEEK_CUR);
                    
                    if (risk_size > (100 * 1024 * 1024)) {
                        proj.high_risk_keys.push_back("[array_overflow]");
                        break;
                    }
                }
                // Skip rest if we bailed early
                if (arr_len > 1000) {
                    _fseeki64(f, static_cast<int64_t>((arr_len - 1000) * elem_size), SEEK_CUR);
                }
            } else {
                _fseeki64(f, static_cast<int64_t>(risk_size), SEEK_CUR);
            }
        } else {
            // Scalar - skip fixed size
            _fseeki64(f, static_cast<int64_t>(GetGGUFTypeSize(val_type)), SEEK_CUR);
        }

        proj.metadata_heap_risk += risk_size;
    }

    static void SkipTensorInfo(FILE* f, GGUFMemoryProjection& proj) {
        uint64_t name_len = ReadULEB128(f);
        _fseeki64(f, static_cast<int64_t>(name_len), SEEK_CUR); // Skip name
        
        uint32_t n_dims;
        fread(&n_dims, 4, 1, f);
        _fseeki64(f, n_dims * 8, SEEK_CUR); // Skip dimensions
        
        uint32_t type;
        fread(&type, 4, 1, f);
        
        uint64_t offset;
        fread(&offset, 8, 1, f);
    }

    static uint64_t GetGGUFTypeSize(uint32_t type) {
        switch(type) {
            case 0: return 1;  // UINT8
            case 1: return 1;  // INT8
            case 2: return 2;  // UINT16
            case 3: return 2;  // INT16
            case 4: return 4;  // UINT32
            case 5: return 4;  // INT32
            case 6: return 5;  // FLOAT32
            case 7: return 6;  // BOOL
            case 8: return 0;  // STRING (variable)
            case 9: return 0;  // ARRAY (variable)
            case 10: return 8; // UINT64
            case 11: return 8; // INT64
            case 12: return 8; // FLOAT64
            default: return 1;
        }
    }
};

} // namespace
```

## 2. RawrXD_SafeGGUFStream.hpp
*Robust replacement for std::ifstream with corruption detection and automatic large-string skipping.*

```cpp
#pragma once
#include <windows.h>
#include <cstdint>
#include <string>
#include <vector>
#include <functional>
#include <stdexcept>

namespace RawrXD::Tools {

// Memory-mapped file handle with automatic cleanup
class MMapHandle {
    HANDLE hFile = INVALID_HANDLE_VALUE;
    HANDLE hMapping = nullptr;
    void* pView = nullptr;
    size_t sz = 0;
public:
    MMapHandle(const char* path) {
        hFile = CreateFileA(path, GENERIC_READ, FILE_SHARE_READ, 
                           nullptr, OPEN_EXISTING, FILE_FLAG_SEQUENTIAL_SCAN, nullptr);
        if (hFile == INVALID_HANDLE_VALUE) 
            throw std::runtime_error("Failed to open file for mmap");
        
        LARGE_INTEGER size;
        GetFileSizeEx(hFile, &size);
        sz = static_cast<size_t>(size.QuadPart);
        
        hMapping = CreateFileMapping(hFile, nullptr, PAGE_READONLY, 0, 0, nullptr);
        if (!hMapping) {
            CloseHandle(hFile);
            throw std::runtime_error("CreateFileMapping failed");
        }
        
        pView = MapViewOfFile(hMapping, FILE_MAP_READ, 0, 0, 0);
        if (!pView) {
            CloseHandle(hMapping);
            CloseHandle(hFile);
            throw std::runtime_error("MapViewOfFile failed");
        }
    }
    
    ~MMapHandle() {
        if (pView) UnmapViewOfFile(pView);
        if (hMapping) CloseHandle(hMapping);
        if (hFile != INVALID_HANDLE_VALUE) CloseHandle(hFile);
    }
    
    const uint8_t* data() const { return static_cast<const uint8_t*>(pView); }
    size_t size() const { return sz; }
};

class SafeGGUFParser {
    const uint8_t* data = nullptr;
    size_t size = 0;
    size_t pos = 0;
    
    // Configuration
    static constexpr size_t MAX_STRING_ALLOC = 50 * 1024 * 1024; // 50MB hard cap
    
public:
    struct ParseCallbacks {
        std::function<bool(const std::string& key, uint32_t type, uint64_t size)> onMetadata;
        std::function<void(const std::string& name, uint32_t type, const std::vector<uint64_t>& dims, uint64_t offset)> onTensor;
    };

    explicit SafeGGUFParser(const char* filepath) {
        MMapHandle mmap(filepath); // Load into temp scope to copy if needed, or keep mapped
        // For zero-copy, you'd keep the mmap alive. Here we demonstrate safe access.
        data = mmap.data();
        size = mmap.size();
        // Note: In real implementation, store the MMapHandle as member to keep view valid
    }

    void Parse(ParseCallbacks& cb, bool skip_large_strings = true) {
        if (size < 32) throw std::runtime_error("File too small for GGUF");
        
        // Validate Magic
        if (memcmp(data, "GGUF", 4) != 0) 
            throw std::runtime_error("Invalid GGUF magic bytes");
        
        pos = 4;
        uint32_t version = ReadU32();
        if (version < 2) throw std::runtime_error("Only GGUF v2+ supported for large models");
        
        uint64_t tensor_count = ReadU64();
        uint64_t metadata_count = ReadU64();

        // Parse Metadata
        for (uint64_t i = 0; i < metadata_count && pos < size; ++i) {
            auto key = ReadString();
            if (key.empty() && pos >= size) break; // Corruption guard
            
            uint32_t val_type = ReadU32();
            
            bool shouldLoad = true;
            uint64_t value_size = 0;
            
            if (val_type == 8) { // String
                uint64_t len = ReadU64();
                if (len > MAX_STRING_ALLOC && skip_large_strings) {
                    // Skip without allocating
                    pos += static_cast<size_t>(len);
                    shouldLoad = false;
                    value_size = len;
                } else if (len > size - pos) {
                    throw std::runtime_error("String length exceeds file bounds (corruption?)");
                } else {
                    // Safe to allocate
                    std::string value(reinterpret_cast<const char*>(data + pos), static_cast<size_t>(len));
                    pos += static_cast<size_t>(len);
                    shouldLoad = cb.onMetadata ? cb.onMetadata(key, val_type, len) : true;
                }
            } 
            else if (val_type == 9) { // Array
                uint32_t arr_type = ReadU32();
                uint64_t arr_len = ReadU64();
                uint64_t elem_sz = GetTypeSize(arr_type);
                
                if (arr_type == 8) { // Array of strings (tokens/merges)
                    // Calculate total size without loading
                    size_t array_start = pos;
                    uint64_t total_str_bytes = 0;
                    
                    for (uint64_t j = 0; j < arr_len && pos < size; ++j) {
                        uint64_t s_len = ReadU64();
                        total_str_bytes += s_len + 8;
                        pos += static_cast<size_t>(s_len);
                    }
                    
                    if (total_str_bytes > MAX_STRING_ALLOC && skip_large_strings) {
                        shouldLoad = false;
                        value_size = total_str_bytes;
                    } else {
                        pos = array_start; // Reset to parse properly
                        shouldLoad = cb.onMetadata ? cb.onMetadata(key, val_type, arr_len) : true;
                        if (!shouldLoad) {
                            // Skip the array
                            for (uint64_t j = 0; j < arr_len; ++j) {
                                uint64_t s_len = ReadU64();
                                pos += static_cast<size_t>(s_len);
                            }
                        }
                    }
                } else {
                    // Fixed-size array - easy skip
                    uint64_t skip_bytes = arr_len * elem_sz;
                    if (skip_bytes > size - pos) 
                        throw std::runtime_error("Array bounds exceed file size");
                    pos += static_cast<size_t>(skip_bytes);
                    shouldLoad = cb.onMetadata ? cb.onMetadata(key, val_type, arr_len) : false;
                }
            } else {
                // Scalar
                uint64_t sz = GetTypeSize(val_type);
                if (sz == 0) throw std::runtime_error("Unknown scalar type");
                pos += static_cast<size_t>(sz);
                shouldLoad = cb.onMetadata ? cb.onMetadata(key, val_type, sz) : true;
            }
            
            if (!shouldLoad) {
                fprintf(stderr, "[GGUF-SAFE] Skipped '%s' (type=%u, size=%llu)\n", 
                        key.c_str(), val_type, value_size);
            }
        }

        // Parse Tensor Info (lightweight)
        for (uint64_t i = 0; i < tensor_count && pos < size; ++i) {
            auto name = ReadString();
            uint32_t n_dims = ReadU32();
            std::vector<uint64_t> dims;
            for (uint32_t d = 0; d < n_dims; ++d) dims.push_back(ReadU64());
            
            uint32_t type = ReadU32();
            uint64_t offset = ReadU64();
            
            if (cb.onTensor) cb.onTensor(name, type, dims, offset);
        }
    }

private:
    uint32_t ReadU32() {
        if (pos + 4 > size) throw std::runtime_error("Unexpected EOF reading u32");
        uint32_t v = *reinterpret_cast<const uint32_t*>(data + pos);
        pos += 4;
        return v;
    }
    
    uint64_t ReadU64() {
        if (pos + 8 > size) throw std::runtime_error("Unexpected EOF reading u64");
        uint64_t v = *reinterpret_cast<const uint64_t*>(data + pos);
        pos += 8;
        return v;
    }
    
    uint64_t ReadULEB128() {
        uint64_t result = 0;
        int shift = 0;
        while (pos < size) {
            uint8_t byte = data[pos++];
            result |= static_cast<uint64_t>(byte & 0x7F) << shift;
            if ((byte & 0x80) == 0) return result;
            shift += 7;
            if (shift >= 64) throw std::runtime_error("ULEB128 overflow");
        }
        throw std::runtime_error("Unexpected EOF in ULEB128");
    }
    
    std::string ReadString() {
        uint64_t len = ReadULEB128();
        if (len > 65535) {
            // Sanity check: metadata keys shouldn't be huge
            throw std::runtime_error("Suspicious string length in metadata key");
        }
        if (pos + len > size) throw std::runtime_error("String extends past EOF");
        
        std::string s(reinterpret_cast<const char*>(data + pos), static_cast<size_t>(len));
        pos += static_cast<size_t>(len);
        return s;
    }
    
    static uint64_t GetTypeSize(uint32_t type) {
        constexpr uint64_t sizes[] = {1,1,2,2,4,4,4,1,0,0,8,8,8};
        return (type < 13) ? sizes[type] : 0;
    }
};

} // namespace
```

## 3. RawrXD_EmergencyDumper.asm
*MASM x64 memory dump utility for post-crash forensics without allocating heap.*

```asm
; RawrXD_EmergencyDumper.asm
; Usage: Invoke when bad_alloc detected to dump GGUF state to disk
; No heap allocation - uses stack + VirtualAlloc reserve only

.code
DumpGGUFContext proc frame
    ; RCX = pFileContext (your StreamingGGUFLoader state)
    ; RDX = DumpFilePath (char*)
    ; R8 = ErrorCode (DWORD)
    
    push rbx
    .pushreg rbx
    push rsi
    .pushreg rsi
    push rdi
    .pushreg rdi
    push r12
    .pushreg r12
    sub rsp, 168        ; Shadow space + locals
    .allocstack 168
    .endprolog
    
    mov rbx, rcx        ; Context
    mov rsi, rdx        ; Path
    mov r12d, r8d       ; Error code
    
    ; Create dump file
    xor ecx, ecx        ; lpSecurityAttributes = NULL
    mov edx, 40000000h  ; GENERIC_WRITE
    xor r8d, r8d        ;dwShareMode
    xor r9d, r9d        ;lpSecurityAttributes
    mov qword ptr [rsp+32], 2  ;CREATE_ALWAYS
    mov qword ptr [rsp+40], 80h ;FILE_ATTRIBUTE_NORMAL
    xor rax, rax
    mov qword ptr [rsp+48], rax ;hTemplateFile
    call CreateFileA
    cmp rax, -1
    je FailedExit
    mov rdi, rax        ;hFile
    
    ; Build header on stack (no heap)
    mov rax, "RAWRAWRX" ;Signature
    mov [rsp+64], rax
    mov [rsp+72], rax
    mov eax, 1          ;Version
    mov [rsp+80], eax
    mov eax, r12d       ;Error code that triggered dump
    mov [rsp+84], eax
    
    ; Write header
    lea r9, [rsp+64]    ;Buffer
    mov r8d, 88         ;Size
    xor edx, edx        ;No overlap
    mov rcx, rdi        ;Handle
    sub rsp, 32
    call WriteFile
    add rsp, 32
    
    ; Dump metadata state from context (rbx)
    ; Assuming context has: file_position, last_key_parsed, tensor_count
    mov rax, [rbx+16]   ;file_position from your struct
    mov [rsp+96], rax
    mov rax, [rbx+24]   ;metadata items parsed
    mov [rsp+104], rax
    
    lea r9, [rsp+96]
    mov r8d, 16
    xor edx, edx
    mov rcx, rdi
    sub rsp, 32
    call WriteFile
    add rsp, 32
    
    ; Close file
    mov rcx, rdi
    call CloseHandle
    
    mov eax, 1          ;Success
    jmp Exit
    
FailedExit:
    xor eax, eax        ;Failed
    
Exit:
    add rsp, 168
    pop r12
    pop rdi
    pop rsi
    pop rbx
    ret

DumpGGUFContext endp

; Fast corruption scanner - finds first invalid ULEB128
; RCX = Buffer, RDX = MaxScanSize
; Returns RAX = offset of corruption or -1 if clean
ScanCorruption proc frame
    push rbx
    .pushreg rbx
    push rdi
    .pushreg rdi
    sub rsp, 40
    .allocstack 40
    .endprolog
    
    mov rbx, rcx
    mov rdi, rdx
    xor r8, r8          ;Position
    
ScanLoop:
    cmp r8, rdi
    jae CleanExit
    
    xor ecx, ecx        ;ULEB value
    xor edx, edx        ;Shift
    mov r9, r8          ;Start of this ULEB
    
ByteLoop:
    cmp r9, rdi
    jae CorruptExit     ;Truncated
    
    movzx eax, byte ptr [rbx+r9]
    inc r9
    
    ; Check if shift would overflow 64-bit
    cmp edx, 63
    ja CorruptExit      ;Shift too big
    
    mov r10d, eax
    and r10d, 7Fh
    shl r10, cl         ;Apply shift
    or rcx, r10
    
    add edx, 7
    
    test al, 80h
    jnz ByteLoop        ;More bytes coming
    
    ; Valid ULEB, advance position
    mov r8, r9
    jmp ScanLoop
    
CorruptExit:
    mov rax, r8         ;Return offset of corruption
    jmp Exit2
    
CleanExit:
    mov rax, -1         ;No corruption found
    
Exit2:
    add rsp, 40
    pop rdi
    pop rbx
    ret
ScanCorruption endp

end
