### 1. **Bulletproof Metadata Parser** (Replaces ParseMetadata)
```cpp
bool StreamingGGUFLoader::ParseMetadataRobust() {
    if (!file_.is_open()) return false;
    
    // Win32 MMF for true zero-copy when available
    HANDLE hFile = reinterpret_cast<HANDLE>(_get_osfhandle(_fileno(file_.native_handle())));
    HANDLE hMap = CreateFileMapping(hFile, NULL, PAGE_READONLY, 0, 0, NULL);
    
    uint64_t* pTensorCount = nullptr;
    uint64_t tensor_count = 0;
    
    // Phase 1: Skip to tensor count with bounds checking
    try {
        // Read kv_count safely
        uint64_t kv_count = 0;
        if (!ReadUint64(kv_count)) throw std::runtime_error("Failed to read kv_count");
        
        // Pre-allocate metadata hash map (avoid rehashing)
        metadata_.reserve(static_cast<size_t>(std::min(kv_count, 65536ULL)));
        
        // Phase 2: Parse key-value pairs with surgical skipping
        for (uint64_t i = 0; i < kv_count; ++i) {
            if (!ParseSingleMetadataEntry(i)) {
                fprintf(stderr, "[ROBUST] Parse failed at entry %llu, attempting recovery...\n", i);
                if (!RecoverFromParseError()) return false;
            }
        }
        
        // Phase 3: Tensor index (critical for 800B models)
        uint64_t tensor_count_raw = 0;
        if (!ReadUint64(tensor_count_raw)) throw std::runtime_error("Failed to read tensor_count");
        tensor_count = tensor_count_raw;
        
    } catch (const std::exception& e) {
        fprintf(stderr, "[ROBUST] ParseMetadata exception: %s\n", e.what());
        if (hMap) CloseHandle(hMap);
        return false;
    }
    
    if (hMap) CloseHandle(hMap);
    tensor_count_ = tensor_count;
    return true;
}

bool StreamingGGUFLoader::ParseSingleMetadataEntry(uint64_t index) {
    // Read key with length validation
    uint64_t key_len = 0;
    if (!ReadUint64(key_len) || key_len > 4096) {  // Keys >4KB are suspicious
        fprintf(stderr, "[ROBUST] Suspicious key length: %llu at entry %llu\n", key_len, index);
        return false;
    }
    
    std::string key;
    key.resize(key_len);
    if (!file_.read(key.data(), key_len)) return false;
    
    // Read type
    gguf_type type;
    if (!file_.read(reinterpret_cast<char*>(&type), sizeof(type))) return false;
    
    // Route to safe handlers
    switch (type) {
