```cpp
bool StreamingGGUFLoader::ReadStringRobust(const std::string& key) {
    uint64_t len = 0;
    if (!ReadUint64(len)) return false;
    
    // Hard limits for BigDaddyG models (prevents 4GB allocation attacks)
    constexpr uint64_t ABSOLUTE_MAX_STRING = 512 * 1024 * 1024;  // 512MB absolute ceiling
    constexpr uint64_t WARN_THRESHOLD = 10 * 1024 * 1024;        // 10MB warning
    
    if (len > ABSOLUTE_MAX_STRING) {
        fprintf(stderr, "[ROBUST] FATAL: String '%s' claims %llu MB (corruption?)\n", 
                key.c_str(), len / (1024*1024));
        SeekRelative(len);  // Skip to keep file alignment
        metadata_[key] = "[CORRUPTION_SKIP]";
        return true;  // Don't crash, mark as skipped
    }
    
    // Strategic skip for known problematic keys
    const bool is_tokenizer_data = (key.find("tokenizer.") == 0) || 
                                   (key.find("merges") != std::string::npos);
    
    if (len > WARN_THRESHOLD || is_tokenizer_data) {
        if (verbose_) {
            fprintf(stderr, "[ROBUST] Lazy-skipping '%s' (%llu bytes)\n", key.c_str(), len);
        }
        SeekRelative(len);
        metadata_[key] = "[LAZY_SKIPPED:" + std::to_string(len) + "]";
        return true;
    }
    
    // Safe allocation with fallback
    std::string value;
    try {
        value.reserve(static_cast<size_t>(len));
        value.resize(static_cast<size_t>(len));
    } catch (const std::bad_alloc&) {
        fprintf(stderr, "[ROBUST] Allocation failed for '%s' (%llu bytes), skipping\n", key.c_str(), len);
        SeekRelative(len);
        metadata_[key] = "[ALLOC_FAIL:" + std::to_string(len) + "]";
        return true;
    }
    
    if (!file_.read(value.data(), len)) return false;
    metadata_[key] = std::move(value);
    return true;
}

bool StreamingGGUFLoader::ReadArrayRobust(const std::string& key) {
    gguf_type elem_type;
    uint64_t count = 0;
    
    if (!file_.read(reinterpret_cast<char*>(&elem_type), sizeof(elem_type))) return false;
    if (!ReadUint64(count)) return false;
    
    // 800B model protection: arrays >100M elements are suspicious
    if (count > 100000000ULL) {
        fprintf(stderr, "[ROBUST] Suspicious array count %llu in '%s', skipping\n", count, key.c_str());
        // Calculate skip size based on element type
        uint64_t elem_size = GetGGUFTypeSize(elem_type);
        SeekRelative(count * elem_size);
        metadata_[key] = "[ARRAY_SKIP:" + std::to_string(count) + "]";
        return true;
    }
    
    // Route to typed array readers...
    switch (elem_type) {
        case GGUF_TYPE_STRING: return ReadStringArrayRobust(key, count);
        case GGUF_TYPE_UINT32: return ReadNumericArray<uint32_t>(key, count);
        default: {
            // Generic skip for unsupported array types
            uint64_t elem_size = GetGGUFTypeSize(elem_type);
            SeekRelative(count * elem_size);
            metadata_[key] = "[UNSUPPORTED_ARRAY]";
            return true;
        }
    }
}
