class MemoryMappedTensorStore {
    HANDLE hFile_ = INVALID_HANDLE_VALUE;
    HANDLE hMapping_ = NULL;
    void* pBase_ = nullptr;
    size_t mapSize_ = 0;
    
public:
    ~MemoryMappedTensorStore() {
        if (pBase_) UnmapViewOfFile(pBase_);
        if (hMapping_) CloseHandle(hMapping_);
        if (hFile_ != INVALID_HANDLE_VALUE) CloseHandle(hFile_);
    }
    
    // Maps only the tensor data region, not metadata
    bool Initialize(const wchar_t* wpath, uint64_t tensor_offset, uint64_t tensor_size) {
        hFile_ = CreateFileW(wpath, GENERIC_READ, FILE_SHARE_READ, NULL, 
                            OPEN_EXISTING, FILE_FLAG_RANDOM_ACCESS, NULL);
        if (hFile_ == INVALID_HANDLE_VALUE) return false;
        
        // Map only what we need (critical for 800B models)
        DWORD offsetHigh = static_cast<DWORD>(tensor_offset >> 32);
        DWORD offsetLow = static_cast<DWORD>(tensor_offset & 0xFFFFFFFF);
        
        hMapping_ = CreateFileMapping(hFile_, NULL, PAGE_READONLY, 
                                      static_cast<DWORD>((tensor_offset + tensor_size) >> 32),
                                      static_cast<DWORD>((tensor_offset + tensor_size) & 0xFFFFFFFF), 
                                      NULL);
        if (!hMapping_) return false;
        
        pBase_ = MapViewOfFile(hMapping_, FILE_MAP_READ, offsetHigh, offsetLow, 
                               static_cast<SIZE_T>(tensor_size));
        return pBase_ != nullptr;
    }
    
    // Returns aligned pointer for AVX-512 operations
    void* GetTensorPtr(uint64_t local_offset = 0) const {
        return static_cast<char*>(pBase_) + local_offset;
    }
};

